15	namespace rime {
16	
17	class RIME_DLL Translation {
18	 public:
19	  Translation() = default;
20	  virtual ~Translation() = default;
21	
22	  // A translation may contain multiple results, looks
23	  // something like a generator of candidates.
24	  virtual bool Next() = 0;
25	
26	  virtual an<Candidate> Peek() = 0;
27	
28	  // should it provide the next candidate (negative value, zero) or
29	  // should it give up the chance for other translations (positive)?
30	  virtual int Compare(an<Translation> other, const CandidateList& candidates);
31	
32	  bool exhausted() const { return exhausted_; }
33	
34	 protected:
35	  void set_exhausted(bool exhausted) { exhausted_ = exhausted; }
36	
37	 private:
38	  bool exhausted_ = false;
39	};
40	
41	class UniqueTranslation : public Translation {
42	 public:
43	  UniqueTranslation(an<Candidate> candidate) : candidate_(candidate) {
44	    set_exhausted(!candidate);
45	  }
46	
47	  bool Next();
48	  an<Candidate> Peek();
49	
50	 protected:
51	  an<Candidate> candidate_;
52	};
