84	
85	class MergedTranslation : public Translation {
86	 public:
87	  explicit MergedTranslation(const CandidateList& previous_candidates);
88	
89	  bool Next();
90	  an<Candidate> Peek();
91	
92	  MergedTranslation& operator+=(an<Translation> t);
93	
