95	
96	 protected:
97	  void Elect();
98	
99	  const CandidateList& previous_candidates_;
100	  vector<of<Translation>> translations_;
101	  size_t elected_ = 0;
102	};
103	
104	class CacheTranslation : public Translation {
105	 public:
106	  CacheTranslation(an<Translation> translation);
107	
108	  virtual bool Next();
109	  virtual an<Candidate> Peek();
110	
111	 protected:
112	  an<Translation> translation_;
113	  an<Candidate> cache_;
114	};
115	
116	template <class T, class... Args>
117	inline an<Translation> Cached(Args&&... args) {
118	  return New<CacheTranslation>(New<T>(std::forward<Args>(args)...));
119	}
