132	class PrefetchTranslation : public Translation {
133	 public:
134	  PrefetchTranslation(an<Translation> translation);
135	
136	  virtual bool Next();
137	  virtual an<Candidate> Peek();
138	
139	 protected:
140	  virtual bool Replenish() { return false; }
